    fn extract_trace_context_rejects_empty_strings() {
        let mut envelope = test_envelope();
        envelope.trace_id = Some(String::new());
        envelope.span_id = Some("def456".to_string());
        assert!(extract_trace_context(&envelope).is_none());
    }

