  1→//! GenAI and Agent OS metrics instruments.
  2→//!
  3→//! Creates OTel metrics following the GenAI semantic conventions
  4→//! and Life-specific operational metrics.
  5→
  6→use opentelemetry::metrics::{Counter, Gauge, Histogram, Meter};
  7→use opentelemetry::{KeyValue, global};
  8→use std::time::Duration;
  9→
 10→use crate::semconv;
 11→
 12→/// Collection of pre-created GenAI and Agent OS metric instruments.
 13→///
 14→/// Created once via [`GenAiMetrics::new`] and shared across the application.
 15→pub struct GenAiMetrics {
 16→    /// `gen_ai.client.token.usage` — histogram of token counts per request.
 17→    pub token_usage: Histogram<u64>,
 18→
 19→    /// `gen_ai.client.operation.duration` — histogram of LLM call duration in seconds.
 20→    pub operation_duration: Histogram<f64>,
 21→
 22→    /// `life.tool.executions` — counter of tool executions by name and status.
 23→    pub tool_executions: Counter<u64>,
 24→
 25→    /// `life.budget.tokens_remaining` — gauge of remaining token budget.
 26→    pub budget_tokens_remaining: Gauge<u64>,
 27→
 28→    /// `life.budget.cost_remaining_usd` — gauge of remaining cost budget.
 29→    pub budget_cost_remaining: Gauge<f64>,
 30→
 31→    /// `life.mode.transitions` — counter of operating mode transitions.
 32→    pub mode_transitions: Counter<u64>,
 33→}
 34→
 35→impl GenAiMetrics {
 36→    /// Create all metric instruments from the global meter provider.
 37→    pub fn new(service_name: &str) -> Self {
 38→        let meter = global::meter(service_name);
 39→        Self::from_meter(&meter)
 40→    }
 41→
 42→    /// Create all metric instruments from a specific meter.
 43→    pub fn from_meter(meter: &Meter) -> Self {
 44→        let token_usage = meter
 45→            .u64_histogram("gen_ai.client.token.usage")
 46→            .with_description("Number of tokens used per GenAI request")
 47→            .with_unit("token")
 48→            .build();
 49→
 50→        let operation_duration = meter
 51→            .f64_histogram("gen_ai.client.operation.duration")
 52→            .with_description("Duration of GenAI operations")
 53→            .with_unit("s")
 54→            .with_boundaries(vec![0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0, 30.0, 60.0, 120.0])
 55→            .build();
 56→
 57→        let tool_executions = meter
 58→            .u64_counter("life.tool.executions")
 59→            .with_description("Number of tool executions")
 60→            .build();
 61→
 62→        let budget_tokens_remaining = meter
 63→            .u64_gauge("life.budget.tokens_remaining")
 64→            .with_description("Remaining token budget")
 65→            .with_unit("token")
 66→            .build();
 67→
 68→        let budget_cost_remaining = meter
 69→            .f64_gauge("life.budget.cost_remaining_usd")
 70→            .with_description("Remaining cost budget in USD")
 71→            .with_unit("USD")
 72→            .build();
 73→
 74→        let mode_transitions = meter
 75→            .u64_counter("life.mode.transitions")
 76→            .with_description("Number of operating mode transitions")
 77→            .build();
 78→
 79→        Self {
 80→            token_usage,
 81→            operation_duration,
 82→            tool_executions,
 83→            budget_tokens_remaining,
 84→            budget_cost_remaining,
 85→            mode_transitions,
 86→        }
 87→    }
 88→
 89→    /// Record token usage for a GenAI operation.
 90→    pub fn record_token_usage(
 91→        &self,
 92→        model: &str,
 93→        operation: &str,
 94→        input_tokens: u64,
 95→        output_tokens: u64,
 96→    ) {
 97→        let base_attrs = [
 98→            KeyValue::new(semconv::GEN_AI_REQUEST_MODEL, model.to_string()),
 99→            KeyValue::new(semconv::GEN_AI_OPERATION_NAME, operation.to_string()),
100→        ];
101→
102→        // Record input tokens
103→        let mut input_attrs = base_attrs.to_vec();
104→        input_attrs.push(KeyValue::new("gen_ai.token.type", "input"));
105→        self.token_usage.record(input_tokens, &input_attrs);
106→
107→        // Record output tokens
108→        let mut output_attrs = base_attrs.to_vec();
109→        output_attrs.push(KeyValue::new("gen_ai.token.type", "output"));
110→        self.token_usage.record(output_tokens, &output_attrs);
111→    }
112→
113→    /// Record the duration of a GenAI operation.
114→    pub fn record_operation_duration(&self, model: &str, operation: &str, duration: Duration) {
115→        self.operation_duration.record(
116→            duration.as_secs_f64(),
117→            &[
118→                KeyValue::new(semconv::GEN_AI_REQUEST_MODEL, model.to_string()),
119→                KeyValue::new(semconv::GEN_AI_OPERATION_NAME, operation.to_string()),
120→            ],
121→        );
122→    }
123→
124→    /// Record a tool execution.
125→    pub fn record_tool_execution(&self, tool_name: &str, status: &str) {
126→        self.tool_executions.add(
127→            1,
128→            &[
129→                KeyValue::new(semconv::GEN_AI_TOOL_NAME, tool_name.to_string()),
130→                KeyValue::new(semconv::LIFE_TOOL_STATUS, status.to_string()),
131→            ],
132→        );
133→    }
134→
135→    /// Update the remaining budget gauge.
136→    pub fn record_budget(&self, tokens_remaining: u64, cost_remaining_usd: f64) {
137→        self.budget_tokens_remaining.record(tokens_remaining, &[]);
138→        self.budget_cost_remaining.record(cost_remaining_usd, &[]);
139→    }
140→
141→    /// Record a mode transition.
142→    pub fn record_mode_transition(&self, from_mode: &str, to_mode: &str) {
