  1→//! Vigil — observability foundation for the Life Agent OS.
  2→//!
  3→//! Provides a unified telemetry pipeline combining structured logging,
  4→//! OpenTelemetry distributed tracing, and metrics collection with
  5→//! GenAI semantic conventions.
  6→//!
  7→//! # Usage
  8→//!
  9→//! ```no_run
 10→//! use vigil::{VigConfig, init_telemetry};
 11→//!
 12→//! # fn main() -> Result<(), vigil::VigError> {
 13→//! let config = VigConfig::for_service("arcan").with_env_overrides();
 14→//! let _guard = init_telemetry(config)?;
 15→//!
 16→//! // All tracing macros now emit structured logs and (if configured) OTel spans.
