 18→//! # Ok(())
 19→//! # }
 20→//! ```
 21→//!
 22→//! If no OTLP endpoint is configured, Vigil degrades gracefully to
 23→//! structured logging only via `tracing-subscriber`.
 24→
 25→pub mod config;
 26→pub mod metrics;
 27→pub mod semconv;
 28→pub mod spans;
 29→
 30→pub use config::{LogFormat, OtlpProtocol, VigConfig};
 31→pub use metrics::GenAiMetrics;
