 37→use tracing_subscriber::EnvFilter;
 38→use tracing_subscriber::prelude::*;
 39→
 40→/// Errors during telemetry initialization.
 41→#[derive(Debug, thiserror::Error)]
 42→pub enum VigError {
 43→    #[error("failed to build OTLP span exporter: {0}")]
 44→    SpanExporter(String),
 45→
 46→    #[error("failed to build OTLP metric exporter: {0}")]
 47→    MetricExporter(String),
 48→
 49→    #[error("failed to initialize tracing subscriber: {0}")]
 50→    Subscriber(String),
 51→}
 52→
 53→/// Guard that flushes and shuts down telemetry providers on drop.
 54→///
 55→/// Hold this in your `main()` for the lifetime of the application.
 56→pub struct VigGuard {
 57→    tracer_provider: Option<SdkTracerProvider>,
 58→    meter_provider: Option<SdkMeterProvider>,
 59→}
 60→
 61→impl Drop for VigGuard {
 62→    fn drop(&mut self) {
 63→        if let Some(ref tp) = self.tracer_provider {
 64→            let _ = tp.shutdown();
 65→        }
 66→        if let Some(ref mp) = self.meter_provider {
 67→            let _ = mp.shutdown();
 68→        }
 69→    }
 70→}
 71→
 72→/// Initialize the Vigil telemetry pipeline.
 73→///
 74→/// Sets up:
 75→/// 1. `tracing-subscriber` with `EnvFilter` + formatted output (pretty or JSON)
 76→/// 2. `tracing-opentelemetry` layer bridging to OTel SDK (if endpoint configured)
 77→/// 3. OTLP exporter for traces (if endpoint configured)
 78→/// 4. OTLP exporter for metrics (if endpoint configured)
 79→///
 80→/// Returns a [`VigGuard`] that flushes telemetry on drop.
 81→///
 82→/// If no OTLP endpoint is set, only structured logging is configured.
 83→pub fn init_telemetry(config: VigConfig) -> Result<VigGuard, VigError> {
 84→    let env_filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info"));
 85→
 86→    if let Some(ref endpoint) = config.otlp_endpoint {
 87→        // Full pipeline: structured logging + OTel traces + metrics
 88→        init_with_otel(config.clone(), endpoint, env_filter)
 89→    } else {
 90→        // Graceful degradation: structured logging only
 91→        init_logging_only(&config, env_filter)
 92→    }
 93→}
 94→
 95→/// Initialize with full OTel pipeline.
 96→fn init_with_otel(
 97→    config: VigConfig,
 98→    endpoint: &str,
 99→    env_filter: EnvFilter,
100→) -> Result<VigGuard, VigError> {
101→    let resource = Resource::builder()
102→        .with_service_name(config.service_name.clone())
103→        .build();
104→
105→    // Build tracer provider
106→    let tracer_provider = build_tracer_provider(&config, endpoint, resource.clone())?;
107→    global::set_tracer_provider(tracer_provider.clone());
108→
109→    // Build meter provider
110→    let meter_provider = build_meter_provider(&config, endpoint, resource)?;
111→    global::set_meter_provider(meter_provider.clone());
112→
113→    // Create OTel tracing layer
114→    let tracer = tracer_provider.tracer(config.service_name.clone());
115→    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);
116→
117→    // Build subscriber with OTel layer + fmt layer
118→    let registry = tracing_subscriber::registry().with(otel_layer);
119→
120→    match config.log_format {
121→        LogFormat::Json => {
122→            let fmt_layer = tracing_subscriber::fmt::layer()
123→                .json()
124→                .with_filter(env_filter);
125→            registry
126→                .with(fmt_layer)
127→                .try_init()
128→                .map_err(|e| VigError::Subscriber(e.to_string()))?;
129→        }
130→        LogFormat::Pretty => {
131→            let fmt_layer = tracing_subscriber::fmt::layer().with_filter(env_filter);
132→            registry
133→                .with(fmt_layer)
134→                .try_init()
135→                .map_err(|e| VigError::Subscriber(e.to_string()))?;
136→        }
137→    }
138→
139→    Ok(VigGuard {
140→        tracer_provider: Some(tracer_provider),
141→        meter_provider: Some(meter_provider),
142→    })
143→}
144→
145→/// Initialize with logging only (no OTel export).
146→fn init_logging_only(config: &VigConfig, env_filter: EnvFilter) -> Result<VigGuard, VigError> {
147→    match config.log_format {
148→        LogFormat::Json => {
149→            tracing_subscriber::registry()
150→                .with(
151→                    tracing_subscriber::fmt::layer()
152→                        .json()
153→                        .with_filter(env_filter),
154→                )
155→                .try_init()
156→                .map_err(|e| VigError::Subscriber(e.to_string()))?;
157→        }
158→        LogFormat::Pretty => {
159→            tracing_subscriber::registry()
160→                .with(tracing_subscriber::fmt::layer().with_filter(env_filter))
161→                .try_init()
162→                .map_err(|e| VigError::Subscriber(e.to_string()))?;
163→        }
164→    }
165→
166→    Ok(VigGuard {
167→        tracer_provider: None,
168→        meter_provider: None,
169→    })
170→}
171→
172→/// Build an OTLP tracer provider.
173→fn build_tracer_provider(
174→    config: &VigConfig,
175→    endpoint: &str,
176→    resource: Resource,
177→) -> Result<SdkTracerProvider, VigError> {
178→    let exporter = match config.otlp_protocol {
179→        OtlpProtocol::Grpc => {
180→            let mut builder = opentelemetry_otlp::SpanExporter::builder()
181→                .with_tonic()
182→                .with_endpoint(endpoint);
183→
184→            if !config.otlp_headers.is_empty() {
185→                let mut metadata = tonic::metadata::MetadataMap::new();
186→                for (key, value) in &config.otlp_headers {
187→                    if let (Ok(k), Ok(v)) = (key.parse(), value.parse()) {
188→                        metadata.insert(k, v);
189→                    }
190→                }
191→                builder = builder.with_metadata(metadata);
192→            }
193→
194→            builder
195→                .build()
196→                .map_err(|e| VigError::SpanExporter(e.to_string()))?
197→        }
198→        OtlpProtocol::Http => opentelemetry_otlp::SpanExporter::builder()
199→            .with_http()
200→            .with_endpoint(endpoint)
201→            .build()
202→            .map_err(|e| VigError::SpanExporter(e.to_string()))?,
203→    };
204→
205→    let provider = SdkTracerProvider::builder()
206→        .with_batch_exporter(exporter)
207→        .with_resource(resource)
208→        .build();
209→
210→    Ok(provider)
211→}
212→
213→/// Build an OTLP meter provider.
214→fn build_meter_provider(
215→    config: &VigConfig,
216→    endpoint: &str,
217→    resource: Resource,
218→) -> Result<SdkMeterProvider, VigError> {
219→    let exporter = match config.otlp_protocol {
220→        OtlpProtocol::Grpc => {
221→            let mut builder = opentelemetry_otlp::MetricExporter::builder()
222→                .with_tonic()
223→                .with_endpoint(endpoint);
224→
225→            if !config.otlp_headers.is_empty() {
226→                let mut metadata = tonic::metadata::MetadataMap::new();
227→                for (key, value) in &config.otlp_headers {
228→                    if let (Ok(k), Ok(v)) = (key.parse(), value.parse()) {
229→                        metadata.insert(k, v);
230→                    }
231→                }
232→                builder = builder.with_metadata(metadata);
233→            }
234→
235→            builder
236→                .build()
237→                .map_err(|e| VigError::MetricExporter(e.to_string()))?
238→        }
239→        OtlpProtocol::Http => opentelemetry_otlp::MetricExporter::builder()
240→            .with_http()
241→            .with_endpoint(endpoint)
242→            .build()
243→            .map_err(|e| VigError::MetricExporter(e.to_string()))?,
244→    };
245→
246→    let provider = SdkMeterProvider::builder()
247→        .with_periodic_exporter(exporter)
248→        .with_resource(resource)
249→        .build();
250→
251→    Ok(provider)
252→}
