        let e = VigError::Subscriber("sub error".to_string());
        assert!(e.to_string().contains("sub error"));
    }

    #[test]
    fn vig_guard_drop_is_safe() {
        let guard = VigGuard {
            tracer_provider: None,
            meter_provider: None,
        };
        drop(guard);
    }
}

